function solve(points) {
    const MOD = 10**9 + 7;
    points.sort((a, b) => a[0] - b[0] || a[1] - b[1]);

    const yCount = {};
    points.forEach(([x, y]) => {
        yCount[y] = (yCount[y] || 0) + 1;
    });

    let result = 0;

    for (const y in yCount) {
        const cnt = yCount[y];
        const ways = (cnt * (cnt - 1)) / 2;
        result += ways;
    }

    const yList = Object.keys(yCount).sort((a, b) => a - b);
    for (let i = 0; i < yList.length - 1; i++) {
        const y1 = yList[i];
        const y2 = yList[i + 1];
        const cnt1 = yCount[y1];
        const cnt2 = yCount[y2];
        const ways = (cnt1 * (cnt1 - 1) / 2) * (cnt2 * (cnt2 - 1) / 2);
        result += ways;
    }

    return result % MOD;
}
